-- 1. Crear tabla con columnas extendidas
create table if not exists ingredientes (
  id            bigint generated always as identity primary key,
  nombre_inci   text not null unique,
  nombre_comun  text,
  clasificacion text not null check (clasificacion in ('verde','amarillo','rojo')),
  funcion       text not null,
  explicacion   text not null,
  categoria     text,
  tipo_cabello  text,
  sinonimos     text,
  nota_riesgo   text,
  cg_friendly   boolean not null default true
);

-- 1b. AÃ±adir columnas nuevas si no existen (para tablas ya creadas)
alter table ingredientes add column if not exists categoria     text;
alter table ingredientes add column if not exists tipo_cabello  text;
alter table ingredientes add column if not exists sinonimos     text;
alter table ingredientes add column if not exists nota_riesgo   text;

-- 2. Seguridad: lectura pÃºblica
alter table ingredientes enable row level security;

do $$
begin
  if not exists (
    select 1 from pg_policies
    where tablename = 'ingredientes' and policyname = 'Lectura pÃºblica'
  ) then
    execute 'create policy "Lectura pÃºblica" on ingredientes for select using (true)';
  end if;
end $$;

-- 3. Insertar 522 ingredientes
on conflict (nombre_inci) do update set
  nombre_comun = excluded.nombre_comun,
  clasificacion = excluded.clasificacion,
  funcion = excluded.funcion,
  explicacion = excluded.explicacion,
  categoria = excluded.categoria,
  tipo_cabello = excluded.tipo_cabello,
  sinonimos = excluded.sinonimos,
  cg_friendly = excluded.cg_friendly;

